from __future__ import annotations


def _rate(outcomes: list[bool]) -> float:
    if not outcomes:
        raise ValueError("outcomes must be non-empty")
    return sum(1 for outcome in outcomes if outcome) / len(outcomes)


def task_success_rate(outcomes: list[bool]) -> float:
    return _rate(outcomes)


def tool_call_success_rate(outcomes: list[bool]) -> float:
    return _rate(outcomes)


def mean_latency_ms(latencies_ms: list[float]) -> float:
    if not latencies_ms:
        raise ValueError("latencies_ms must be non-empty")
    if any(latency < 0 for latency in latencies_ms):
        raise ValueError("latencies_ms must be non-negative")
    return sum(latencies_ms) / len(latencies_ms)


def failure_breakdown(labels: list[str]) -> dict[str, int]:
    counts: dict[str, int] = {}
    for label in labels:
        cleaned = label.strip()
        if not cleaned:
            continue
        counts[cleaned] = counts.get(cleaned, 0) + 1
    return counts

from __future__ import annotations


def updated_beta_posterior(
    prior_alpha: float,
    prior_beta: float,
    successes: int,
    failures: int,
) -> dict[str, float]:
    if prior_alpha <= 0.0 or prior_beta <= 0.0:
        raise ValueError("prior_alpha and prior_beta must be positive")
    if successes < 0 or failures < 0:
        raise ValueError("successes and failures must be non-negative")
    return {
        "alpha": prior_alpha + successes,
        "beta": prior_beta + failures,
    }


def posterior_benchmark_summary(alpha: float, beta: float) -> dict[str, float]:
    if alpha <= 0.0 or beta <= 0.0:
        raise ValueError("alpha and beta must be positive")
    total = alpha + beta
    posterior_mean = alpha / total
    posterior_variance = alpha * beta / (total * total * (total + 1.0))
    return {
        "posterior_mean": posterior_mean,
        "posterior_variance": posterior_variance,
        "effective_sample_size": total,
    }


def benchmark_belief_route(
    posterior_mean: float,
    posterior_variance: float,
    min_mean: float,
    max_variance: float,
) -> str:
    if not 0.0 <= posterior_mean <= 1.0:
        raise ValueError("posterior_mean must satisfy 0 <= value <= 1")
    if not 0.0 <= posterior_variance <= 1.0:
        raise ValueError("posterior_variance must satisfy 0 <= value <= 1")
    if not 0.0 <= min_mean <= 1.0:
        raise ValueError("min_mean must satisfy 0 <= value <= 1")
    if not 0.0 <= max_variance <= 1.0:
        raise ValueError("max_variance must satisfy 0 <= value <= 1")

    if posterior_mean < min_mean:
        return "fail"
    if posterior_variance > max_variance:
        return "review"
    return "pass"

from __future__ import annotations


def benchmark_manifest(case_buckets: list[str]) -> dict[str, object]:
    if not case_buckets:
        raise ValueError("case_buckets must be non-empty")

    bucket_counts: dict[str, int] = {}
    for bucket in case_buckets:
        cleaned_bucket = bucket.strip()
        if not cleaned_bucket:
            raise ValueError("bucket names must be non-empty")
        bucket_counts[cleaned_bucket] = bucket_counts.get(cleaned_bucket, 0) + 1

    return {
        "total_cases": len(case_buckets),
        "bucket_counts": bucket_counts,
    }


def baseline_snapshot(name: str, metrics: dict[str, float]) -> dict[str, object]:
    cleaned_name = name.strip()
    if not cleaned_name:
        raise ValueError("name must be non-empty")
    if not metrics:
        raise ValueError("metrics must be non-empty")
    return {
        "name": cleaned_name,
        "metrics": metrics,
        "frozen": True,
    }


def benchmark_gate(
    candidate_success: float,
    baseline_success: float,
    min_success: float,
    max_drop: float,
) -> str:
    values = [candidate_success, baseline_success, min_success]
    if any(not 0.0 <= value <= 1.0 for value in values):
        raise ValueError("success metrics must satisfy 0 <= value <= 1")
    if max_drop < 0.0:
        raise ValueError("max_drop must be non-negative")

    if candidate_success < min_success:
        return "fail"
    if baseline_success - candidate_success > max_drop:
        return "review"
    return "pass"

from __future__ import annotations


def confidence_bucket_index(confidence: float, bucket_count: int) -> int:
    if not 0.0 <= confidence <= 1.0:
        raise ValueError("confidence must satisfy 0 <= value <= 1")
    if bucket_count <= 0:
        raise ValueError("bucket_count must be positive")
    if confidence == 1.0:
        return bucket_count - 1
    return int(confidence * bucket_count)


def bucketed_calibration_table(
    confidences: list[float],
    outcomes: list[bool],
    bucket_count: int,
) -> list[dict[str, object]]:
    if not confidences or not outcomes:
        raise ValueError("confidences and outcomes must be non-empty")
    if len(confidences) != len(outcomes):
        raise ValueError("confidences and outcomes must have the same length")
    if bucket_count <= 0:
        raise ValueError("bucket_count must be positive")

    buckets = [
        {
            "bucket": bucket_index,
            "count": 0,
            "mean_confidence": 0.0,
            "accuracy": 0.0,
            "gap": 0.0,
        }
        for bucket_index in range(bucket_count)
    ]

    confidence_sums = [0.0] * bucket_count
    success_sums = [0] * bucket_count
    for confidence, outcome in zip(confidences, outcomes):
        bucket_index = confidence_bucket_index(confidence, bucket_count)
        buckets[bucket_index]["count"] = int(buckets[bucket_index]["count"]) + 1
        confidence_sums[bucket_index] += confidence
        success_sums[bucket_index] += int(outcome)

    for bucket_index, bucket in enumerate(buckets):
        count = int(bucket["count"])
        if count == 0:
            continue
        mean_confidence = confidence_sums[bucket_index] / count
        accuracy = success_sums[bucket_index] / count
        bucket["mean_confidence"] = mean_confidence
        bucket["accuracy"] = accuracy
        bucket["gap"] = abs(mean_confidence - accuracy)

    return buckets


def expected_calibration_error(
    confidences: list[float],
    outcomes: list[bool],
    bucket_count: int,
) -> float:
    table = bucketed_calibration_table(confidences, outcomes, bucket_count)
    total = sum(int(bucket["count"]) for bucket in table)
    if total == 0:
        raise ValueError("at least one bucket count is required")

    return sum(
        int(bucket["count"]) / total * float(bucket["gap"])
        for bucket in table
        if int(bucket["count"]) > 0
    )


def calibration_diagnostic_route(ece: float, max_ece: float) -> str:
    if not 0.0 <= ece <= 1.0:
        raise ValueError("ece must satisfy 0 <= value <= 1")
    if not 0.0 <= max_ece <= 1.0:
        raise ValueError("max_ece must satisfy 0 <= value <= 1")
    if ece > max_ece:
        return "review"
    return "pass"

from __future__ import annotations


def mean_confidence(confidences: list[float]) -> float:
    if not confidences:
        raise ValueError("confidences must be non-empty")
    if any(confidence < 0.0 or confidence > 1.0 for confidence in confidences):
        raise ValueError("confidences must satisfy 0 <= value <= 1")
    return sum(confidences) / len(confidences)


def observed_accuracy(outcomes: list[bool]) -> float:
    if not outcomes:
        raise ValueError("outcomes must be non-empty")
    return sum(1 for outcome in outcomes if outcome) / len(outcomes)


def calibration_gap(mean_confidence_value: float, observed_accuracy_value: float) -> float:
    if not 0.0 <= mean_confidence_value <= 1.0:
        raise ValueError("mean_confidence_value must satisfy 0 <= value <= 1")
    if not 0.0 <= observed_accuracy_value <= 1.0:
        raise ValueError("observed_accuracy_value must satisfy 0 <= value <= 1")
    return abs(mean_confidence_value - observed_accuracy_value)


def calibration_route(
    mean_confidence_value: float,
    observed_accuracy_value: float,
    max_gap: float,
    min_accuracy: float,
) -> str:
    if max_gap < 0.0:
        raise ValueError("max_gap must be non-negative")
    if not 0.0 <= min_accuracy <= 1.0:
        raise ValueError("min_accuracy must satisfy 0 <= value <= 1")

    gap = calibration_gap(mean_confidence_value, observed_accuracy_value)
    if observed_accuracy_value < min_accuracy:
        return "review"
    if gap > max_gap:
        return "review"
    return "pass"

from __future__ import annotations


def _validate_pairs(left: list[object], right: list[object]) -> None:
    if not left or not right:
        raise ValueError("inputs must be non-empty")
    if len(left) != len(right):
        raise ValueError("inputs must have the same length")


def quality_per_cost(qualities: list[float], costs: list[float]) -> float:
    _validate_pairs(qualities, costs)
    if any(cost <= 0 for cost in costs):
        raise ValueError("costs must be positive")
    return sum(qualities) / sum(costs)


def cost_per_success(successes: list[bool], costs: list[float]) -> float:
    _validate_pairs(successes, costs)
    if any(cost < 0 for cost in costs):
        raise ValueError("costs must be non-negative")
    success_count = sum(1 for success in successes if success)
    if success_count == 0:
        raise ValueError("at least one success is required")
    return sum(costs) / success_count


def best_tradeoff_index(qualities: list[float], costs: list[float]) -> int:
    _validate_pairs(qualities, costs)
    if any(cost <= 0 for cost in costs):
        raise ValueError("costs must be positive")
    scores = [quality / cost for quality, cost in zip(qualities, costs)]
    return max(range(len(scores)), key=lambda index: scores[index])

from __future__ import annotations


def _validate_rate(value: float, name: str) -> None:
    if not 0.0 <= value <= 1.0:
        raise ValueError(f"{name} must satisfy 0 <= value <= 1")


def success_delta(baseline_success: float, candidate_success: float) -> float:
    _validate_rate(baseline_success, "baseline_success")
    _validate_rate(candidate_success, "candidate_success")
    return candidate_success - baseline_success


def compare_variant_scores(baseline: dict[str, float], candidate: dict[str, float]) -> str:
    baseline_success = float(baseline.get("success", 0.0))
    candidate_success = float(candidate.get("success", 0.0))
    _validate_rate(baseline_success, "baseline.success")
    _validate_rate(candidate_success, "candidate.success")
    if candidate_success > baseline_success:
        return "candidate"
    if candidate_success < baseline_success:
        return "baseline"

    baseline_latency = float(baseline.get("latency_ms", 0.0))
    candidate_latency = float(candidate.get("latency_ms", 0.0))
    if candidate_latency < baseline_latency:
        return "candidate"
    if candidate_latency > baseline_latency:
        return "baseline"
    return "tie"


def comparison_summary(
    baseline_name: str,
    candidate_name: str,
    baseline_success: float,
    candidate_success: float,
) -> str:
    _validate_rate(baseline_success, "baseline_success")
    _validate_rate(candidate_success, "candidate_success")
    delta = candidate_success - baseline_success
    return (
        f"{candidate_name} vs {baseline_name}: "
        f"success {candidate_success:.2f} vs {baseline_success:.2f} "
        f"(delta {delta:+.2f})"
    )

from __future__ import annotations


def categorize_failure(message: str) -> str:
    lowered = message.strip().lower()
    if not lowered:
        return "unknown"
    if "tool" in lowered or "timeout" in lowered or "rate limit" in lowered:
        return "tool"
    if "policy" in lowered or "guardrail" in lowered or "blocked" in lowered:
        return "policy"
    if "plan" in lowered or "workflow" in lowered or "handoff" in lowered:
        return "workflow"
    if "model" in lowered or "halluc" in lowered:
        return "model"
    return "unknown"


def failure_category_counts(messages: list[str]) -> dict[str, int]:
    counts: dict[str, int] = {}
    for message in messages:
        category = categorize_failure(message)
        counts[category] = counts.get(category, 0) + 1
    return counts


def top_failure_category(messages: list[str]) -> str | None:
    counts = failure_category_counts(messages)
    if not counts:
        return None
    return max(counts.items(), key=lambda item: (item[1], item[0]))[0]

from __future__ import annotations


def weighted_group_score(bucket_to_metrics: dict[str, dict[str, float]]) -> dict[str, float]:
    if not bucket_to_metrics:
        raise ValueError("bucket_to_metrics must be non-empty")

    weighted_sum = 0.0
    total_weight = 0.0
    for bucket_name, metrics in bucket_to_metrics.items():
        cleaned_name = bucket_name.strip()
        if not cleaned_name:
            raise ValueError("bucket names must be non-empty")
        score = float(metrics.get("score", 0.0))
        weight = float(metrics.get("weight", 0.0))
        if not 0.0 <= score <= 1.0:
            raise ValueError("bucket scores must satisfy 0 <= value <= 1")
        if weight <= 0.0:
            raise ValueError("bucket weights must be positive")
        weighted_sum += score * weight
        total_weight += weight

    return {
        "score": weighted_sum / total_weight,
        "weight": total_weight,
    }


def hierarchical_benchmark_summary(group_to_buckets: dict[str, dict[str, dict[str, float]]]) -> dict[str, object]:
    if not group_to_buckets:
        raise ValueError("group_to_buckets must be non-empty")

    group_scores: dict[str, float] = {}
    total_weighted_score = 0.0
    total_weight = 0.0
    for group_name, buckets in group_to_buckets.items():
        cleaned_name = group_name.strip()
        if not cleaned_name:
            raise ValueError("group names must be non-empty")
        group_summary = weighted_group_score(buckets)
        group_scores[cleaned_name] = group_summary["score"]
        total_weighted_score += group_summary["score"] * group_summary["weight"]
        total_weight += group_summary["weight"]

    return {
        "group_scores": group_scores,
        "overall_score": total_weighted_score / total_weight,
    }


def hierarchical_benchmark_route(
    summary: dict[str, object],
    min_overall_score: float,
    min_group_score: float,
) -> str:
    if not 0.0 <= min_overall_score <= 1.0:
        raise ValueError("min_overall_score must satisfy 0 <= value <= 1")
    if not 0.0 <= min_group_score <= 1.0:
        raise ValueError("min_group_score must satisfy 0 <= value <= 1")
    overall_score = float(summary.get("overall_score", -1.0))
    group_scores = summary.get("group_scores")
    if not isinstance(group_scores, dict) or not group_scores:
        raise ValueError("summary.group_scores must be a non-empty dict")
    if not 0.0 <= overall_score <= 1.0:
        raise ValueError("summary.overall_score must satisfy 0 <= value <= 1")

    if overall_score < min_overall_score:
        return "fail"
    if any(float(score) < min_group_score for score in group_scores.values()):
        return "review"
    return "pass"

from __future__ import annotations


def mean_judge_score(scores: list[float]) -> float:
    if not scores:
        raise ValueError("scores must be non-empty")
    if any(score < 0.0 or score > 1.0 for score in scores):
        raise ValueError("scores must satisfy 0 <= score <= 1")
    return sum(scores) / len(scores)


def trace_grade_packet(run_id: str, judge_score: float, step_statuses: list[str]) -> dict[str, object]:
    cleaned_run_id = run_id.strip()
    if not cleaned_run_id:
        raise ValueError("run_id must be non-empty")
    if judge_score < 0.0 or judge_score > 1.0:
        raise ValueError("judge_score must satisfy 0 <= score <= 1")

    cleaned_statuses = [status.strip().lower() for status in step_statuses if status.strip()]
    if not cleaned_statuses:
        raise ValueError("step_statuses must contain at least one non-empty status")

    blocked_or_failed_steps = sum(
        status in {"blocked", "failed"} for status in cleaned_statuses
    )
    return {
        "run_id": cleaned_run_id,
        "judge_score": judge_score,
        "step_statuses": cleaned_statuses,
        "blocked_or_failed_steps": blocked_or_failed_steps,
    }


def judge_trace_route(judge_score: float, blocked_or_failed_steps: int, threshold: float) -> str:
    if judge_score < 0.0 or judge_score > 1.0:
        raise ValueError("judge_score must satisfy 0 <= score <= 1")
    if threshold < 0.0 or threshold > 1.0:
        raise ValueError("threshold must satisfy 0 <= value <= 1")
    if blocked_or_failed_steps < 0:
        raise ValueError("blocked_or_failed_steps must be non-negative")

    if judge_score < threshold:
        return "fail"
    if blocked_or_failed_steps > 0:
        return "review"
    return "pass"

from __future__ import annotations


def paired_outcome_counts(baseline: list[bool], candidate: list[bool]) -> dict[str, int]:
    if not baseline or not candidate:
        raise ValueError("baseline and candidate must be non-empty")
    if len(baseline) != len(candidate):
        raise ValueError("baseline and candidate must have the same length")

    counts = {
        "both_success": 0,
        "baseline_only": 0,
        "candidate_only": 0,
        "both_fail": 0,
    }
    for baseline_ok, candidate_ok in zip(baseline, candidate):
        if baseline_ok and candidate_ok:
            counts["both_success"] += 1
        elif baseline_ok and not candidate_ok:
            counts["baseline_only"] += 1
        elif not baseline_ok and candidate_ok:
            counts["candidate_only"] += 1
        else:
            counts["both_fail"] += 1
    return counts


def mcnemar_statistic(baseline_only: int, candidate_only: int) -> float:
    if baseline_only < 0 or candidate_only < 0:
        raise ValueError("discordant counts must be non-negative")

    discordant = baseline_only + candidate_only
    if discordant == 0:
        return 0.0
    return (abs(baseline_only - candidate_only) - 1) ** 2 / discordant


def paired_significance_route(counts: dict[str, int], threshold: float) -> str:
    if threshold < 0.0:
        raise ValueError("threshold must be non-negative")
    required_keys = {"both_success", "baseline_only", "candidate_only", "both_fail"}
    if set(counts) != required_keys:
        raise ValueError("counts must include both_success, baseline_only, candidate_only, both_fail")

    statistic = mcnemar_statistic(
        int(counts["baseline_only"]),
        int(counts["candidate_only"]),
    )
    if statistic < threshold:
        return "inconclusive"
    if int(counts["candidate_only"]) > int(counts["baseline_only"]):
        return "candidate-better"
    if int(counts["candidate_only"]) < int(counts["baseline_only"]):
        return "baseline-better"
    return "inconclusive"

from __future__ import annotations


def _validate_objectives(maximize_metrics: list[str], minimize_metrics: list[str]) -> tuple[list[str], list[str]]:
    maximize = [metric.strip() for metric in maximize_metrics if metric.strip()]
    minimize = [metric.strip() for metric in minimize_metrics if metric.strip()]
    if not maximize and not minimize:
        raise ValueError("at least one objective metric is required")
    overlap = set(maximize) & set(minimize)
    if overlap:
        raise ValueError("metrics cannot appear in both maximize and minimize")
    return maximize, minimize


def dominates(
    left_metrics: dict[str, float],
    right_metrics: dict[str, float],
    maximize_metrics: list[str],
    minimize_metrics: list[str],
) -> bool:
    maximize, minimize = _validate_objectives(maximize_metrics, minimize_metrics)

    strictly_better = False
    for metric in maximize:
        if metric not in left_metrics or metric not in right_metrics:
            raise ValueError(f"missing metric: {metric}")
        left_value = left_metrics[metric]
        right_value = right_metrics[metric]
        if left_value < right_value:
            return False
        if left_value > right_value:
            strictly_better = True

    for metric in minimize:
        if metric not in left_metrics or metric not in right_metrics:
            raise ValueError(f"missing metric: {metric}")
        left_value = left_metrics[metric]
        right_value = right_metrics[metric]
        if left_value > right_value:
            return False
        if left_value < right_value:
            strictly_better = True

    return strictly_better


def pareto_front(
    variants: dict[str, dict[str, float]],
    maximize_metrics: list[str],
    minimize_metrics: list[str],
) -> list[str]:
    if not variants:
        raise ValueError("variants must be non-empty")
    _validate_objectives(maximize_metrics, minimize_metrics)

    frontier: list[str] = []
    for candidate_name, candidate_metrics in variants.items():
        cleaned_name = candidate_name.strip()
        if not cleaned_name:
            raise ValueError("variant names must be non-empty")
        dominated = False
        for other_name, other_metrics in variants.items():
            if cleaned_name == other_name.strip():
                continue
            if dominates(other_metrics, candidate_metrics, maximize_metrics, minimize_metrics):
                dominated = True
                break
        if not dominated:
            frontier.append(cleaned_name)
    return sorted(frontier)


def pareto_route(
    candidate_name: str,
    variants: dict[str, dict[str, float]],
    maximize_metrics: list[str],
    minimize_metrics: list[str],
) -> str:
    cleaned_name = candidate_name.strip()
    if not cleaned_name:
        raise ValueError("candidate_name must be non-empty")
    if cleaned_name not in variants:
        raise ValueError("candidate_name must exist in variants")
    frontier = pareto_front(variants, maximize_metrics, minimize_metrics)
    if cleaned_name in frontier:
        return "frontier"
    return "dominated"

from __future__ import annotations


def metric_drop(baseline: float, candidate: float) -> float:
    return baseline - candidate


def regression_failed(baseline: float, candidate: float, max_drop: float) -> bool:
    if max_drop < 0:
        raise ValueError("max_drop must be non-negative")
    return metric_drop(baseline, candidate) > max_drop


def regression_report(
    metric_name: str,
    baseline: float,
    candidate: float,
    max_drop: float,
) -> dict[str, object]:
    if not metric_name.strip():
        raise ValueError("metric_name must be non-empty")
    failed = regression_failed(baseline, candidate, max_drop)
    return {
        "metric": metric_name,
        "baseline": baseline,
        "candidate": candidate,
        "drop": metric_drop(baseline, candidate),
        "failed": failed,
    }

from __future__ import annotations


def _validate_rate(value: float, name: str) -> None:
    if not 0.0 <= value <= 1.0:
        raise ValueError(f"{name} must satisfy 0 <= value <= 1")


def risk_adjusted_score(success_rate: float, high_risk_failure_rate: float, risk_penalty: float) -> float:
    _validate_rate(success_rate, "success_rate")
    _validate_rate(high_risk_failure_rate, "high_risk_failure_rate")
    if risk_penalty < 0.0:
        raise ValueError("risk_penalty must be non-negative")
    return success_rate - risk_penalty * high_risk_failure_rate


def benchmark_risk_summary(
    name: str,
    success_rate: float,
    high_risk_failure_rate: float,
    risk_penalty: float,
) -> dict[str, object]:
    cleaned_name = name.strip()
    if not cleaned_name:
        raise ValueError("name must be non-empty")
    score = risk_adjusted_score(success_rate, high_risk_failure_rate, risk_penalty)
    return {
        "name": cleaned_name,
        "success_rate": success_rate,
        "high_risk_failure_rate": high_risk_failure_rate,
        "risk_penalty": risk_penalty,
        "risk_adjusted_score": score,
    }


def risk_adjusted_route(
    candidate_score: float,
    baseline_score: float,
    min_score: float,
    max_drop: float,
) -> str:
    if max_drop < 0.0:
        raise ValueError("max_drop must be non-negative")
    if candidate_score < min_score:
        return "fail"
    if baseline_score - candidate_score > max_drop:
        return "review"
    return "pass"

from __future__ import annotations

import math


def _validate_baseline_success(baseline_success: float) -> None:
    if not 0.0 < baseline_success < 1.0:
        raise ValueError("baseline_success must satisfy 0 < value < 1")


def _validate_z_value(value: float, name: str) -> None:
    if value <= 0.0:
        raise ValueError(f"{name} must be positive")


def required_sample_size(
    baseline_success: float,
    effect_size: float,
    z_alpha: float = 1.96,
    z_beta: float = 0.84,
) -> int:
    _validate_baseline_success(baseline_success)
    if effect_size <= 0.0:
        raise ValueError("effect_size must be positive")
    _validate_z_value(z_alpha, "z_alpha")
    _validate_z_value(z_beta, "z_beta")

    variance = 2.0 * baseline_success * (1.0 - baseline_success)
    z_total = z_alpha + z_beta
    return math.ceil(variance * (z_total / effect_size) ** 2)


def minimum_detectable_effect(
    baseline_success: float,
    sample_size_per_variant: int,
    z_alpha: float = 1.96,
    z_beta: float = 0.84,
) -> float:
    _validate_baseline_success(baseline_success)
    if sample_size_per_variant <= 0:
        raise ValueError("sample_size_per_variant must be positive")
    _validate_z_value(z_alpha, "z_alpha")
    _validate_z_value(z_beta, "z_beta")

    variance = 2.0 * baseline_success * (1.0 - baseline_success)
    z_total = z_alpha + z_beta
    return z_total * math.sqrt(variance / sample_size_per_variant)


def sample_size_route(current_samples_per_variant: int, required_samples_per_variant: int) -> str:
    if current_samples_per_variant < 0:
        raise ValueError("current_samples_per_variant must be non-negative")
    if required_samples_per_variant <= 0:
        raise ValueError("required_samples_per_variant must be positive")
    if current_samples_per_variant >= required_samples_per_variant:
        return "ready"
    return "collect-more"

