def add_span(trace: dict[str, object], name: str, latency_ms: float, status: str) -> dict[str, object]:
    if not name.strip():
        raise ValueError("name must be non-empty")
    if latency_ms < 0:
        raise ValueError("latency_ms must be non-negative")
    if not status.strip():
