def stop_decision(plan: list[dict[str, object]], blockers: list[str], needs_review: bool) -> str:
    if all_steps_done(plan):
        return "done"
    if needs_review:
        return "review"
    if stop_due_to_blockers(blockers):
        return "blocked"
    return "continue"

