import math


def empirical_mean(total_reward: float, pulls: int) -> float:
    if pulls <= 0:
        raise ValueError("pulls must be positive")
    if total_reward < 0.0:
        raise ValueError("total_reward must be non-negative")
    return total_reward / pulls


def ucb_score(
    total_reward: float,
    pulls: int,
    total_rounds: int,
    exploration_weight: float = 2.0,
) -> float:
    if total_rounds <= 0:
        raise ValueError("total_rounds must be positive")
    if pulls <= 0:
        raise ValueError("pulls must be positive")
    if total_rounds < pulls:
        raise ValueError("total_rounds must be greater than or equal to pulls")
    if exploration_weight < 0.0:
        raise ValueError("exploration_weight must be non-negative")

    mean_reward = empirical_mean(total_reward, pulls)
    bonus = math.sqrt(exploration_weight * math.log(total_rounds) / pulls) if total_rounds > 1 else 0.0
    return mean_reward + bonus


def bandit_choice(
    tool_to_stats: dict[str, dict[str, float]],
    total_rounds: int,
    min_pulls: int = 1,
    exploration_weight: float = 2.0,
) -> str:
    if not tool_to_stats:
        raise ValueError("tool_to_stats must be non-empty")
    if total_rounds <= 0:
        raise ValueError("total_rounds must be positive")
    if min_pulls <= 0:
        raise ValueError("min_pulls must be positive")

    underexplored: list[tuple[int, str]] = []
    ranked: list[tuple[float, str]] = []
    for tool_name, stats in tool_to_stats.items():
        cleaned_name = tool_name.strip()
        if not cleaned_name:
            raise ValueError("tool names must be non-empty")
        pulls = int(stats.get("pulls", 0))
        total_reward = float(stats.get("total_reward", 0.0))
        if pulls < 0:
            raise ValueError("pulls must be non-negative")
        if total_reward < 0.0:
            raise ValueError("total_reward must be non-negative")
        if pulls < min_pulls:
            underexplored.append((pulls, cleaned_name))
            continue
        ranked.append(
            (
                ucb_score(
                    total_reward=total_reward,
                    pulls=pulls,
                    total_rounds=total_rounds,
                    exploration_weight=exploration_weight,
                ),
                cleaned_name,
            )
        )

    if underexplored:
        underexplored.sort(key=lambda item: (item[0], item[1]))
        return underexplored[0][1]

    ranked.sort(key=lambda item: (-item[0], item[1]))
    return ranked[0][1]

