def schema_fields(schema: dict[str, object]) -> list[str]:
    properties = schema.get("properties", {})
    if not isinstance(properties, dict):
        return []
    fields: list[str] = []
    for key in properties:
        cleaned = str(key).strip()
        if cleaned:
            fields.append(cleaned)
    return fields


def schema_match_score(argument_names: list[str], field_names: list[str]) -> int:
    wanted = {name.strip() for name in argument_names if name.strip()}
    available = {name.strip() for name in field_names if name.strip()}
    return len(wanted & available)


def best_schema_match(argument_names: list[str], tool_schemas: dict[str, dict[str, object]]) -> str | None:
    best_tool: str | None = None
    best_score = 0
    for tool_name, schema in tool_schemas.items():
        score = schema_match_score(argument_names, schema_fields(schema))
        if score > best_score:
            best_tool = tool_name
            best_score = score
    return best_tool

from __future__ import annotations


def keyword_match_score(intent: str, keywords: list[str]) -> int:
    lowered = intent.strip().lower()
    if not lowered:
        return 0
    return sum(1 for keyword in keywords if keyword.strip().lower() in lowered)


def rank_tools(intent: str, tool_keywords: dict[str, list[str]]) -> list[tuple[str, int]]:
    scores = [
        (tool, keyword_match_score(intent, keywords))
        for tool, keywords in tool_keywords.items()
    ]
    ranked = sorted(scores, key=lambda item: (-item[1], item[0]))
    return [(tool, score) for tool, score in ranked if score > 0]


def pick_tool(intent: str, tool_keywords: dict[str, list[str]]) -> str | None:
    ranked = rank_tools(intent, tool_keywords)
    if not ranked:
        return None
    return ranked[0][0]

