class Solution:
    def threeSum(self, nums: List[int]) -> List[List[int]]:
        nums.sort()
        result: List[List[int]] = []
        n = len(nums)

        for i in range(n - 2):
            if nums[i] > 0:
                break
            if i > 0 and nums[i] == nums[i - 1]:
                continue

            left, right = i + 1, n - 1
            while left < right:
                total = nums[i] + nums[left] + nums[right]
                if total == 0:
                    result.append([nums[i], nums[left], nums[right]])
                    left += 1
                    right -= 1

                    # Skip duplicate pairs for the current fixed first value.
                    while left < right and nums[left] == nums[left - 1]:
                        left += 1
                    while left < right and nums[right] == nums[right + 1]:
                        right -= 1
                elif total < 0:
                    left += 1
                else:
                    right -= 1

        return result

class Solution:
    def reverseWords(self, s: str) -> str:
        chars = list(s)
        length = self._compact_spaces(chars)
        chars = chars[:length]
        self._reverse(chars, 0, len(chars) - 1)

        word_start = 0
        for index in range(len(chars) + 1):
            if index == len(chars) or chars[index] == " ":
                self._reverse(chars, word_start, index - 1)
                word_start = index + 1

        return "".join(chars)

    def _compact_spaces(self, chars: list[str]) -> int:
        write = 0
        read = 0
        n = len(chars)

        while read < n:
            while read < n and chars[read] == " ":
                read += 1
            while read < n and chars[read] != " ":
                chars[write] = chars[read]
                write += 1
                read += 1
            while read < n and chars[read] == " ":
                read += 1
            if read < n:
                chars[write] = " "
                write += 1

        return write

    def _reverse(self, chars: list[str], left: int, right: int) -> None:
        while left < right:
            chars[left], chars[right] = chars[right], chars[left]
            left += 1
            right -= 1

