class Solution:
    def coinChange(self, coins: List[int], amount: int) -> int:
        max_value = amount + 1
        dp = [max_value] * (amount + 1)
        dp[0] = 0
        for coin in coins:
            for total in range(coin, amount + 1):
                dp[total] = min(dp[total], dp[total - coin] + 1)
        return dp[amount] if dp[amount] != max_value else -1

