        }

    length = 0
    tail = head
    current = head
    while current:
        length += 1
        tail = current
        current = current.next

    return {
        "length": length,
        "head": head.val,
        "tail": tail.val,
        "has_cycle": False,
    }


def _has_cycle(head: ListNode) -> bool:
    slow = head
    fast = head
    while fast and fast.next:
        slow = slow.next
        fast = fast.next.next
        if slow is fast:
            return True
    return False

