class Solution:
    def reverseWords(self, s: str) -> str:
        chars = list(s)
        length = self._compact_spaces(chars)
        chars = chars[:length]
        self._reverse(chars, 0, len(chars) - 1)

        word_start = 0
        for index in range(len(chars) + 1):
            if index == len(chars) or chars[index] == " ":
                self._reverse(chars, word_start, index - 1)
                word_start = index + 1

        return "".join(chars)

    def _compact_spaces(self, chars: list[str]) -> int:
        write = 0
        read = 0
        n = len(chars)

        while read < n:
            while read < n and chars[read] == " ":
                read += 1

            while read < n and chars[read] != " ":
                chars[write] = chars[read]
                write += 1
                read += 1

            while read < n and chars[read] == " ":
                read += 1

            if read < n:
                chars[write] = " "
                write += 1

        return write

    def _reverse(self, chars: list[str], left: int, right: int) -> None:
        # Reverse the whole string first, then reverse each word in place.
        while left < right:
            chars[left], chars[right] = chars[right], chars[left]
            left += 1
            right -= 1

class Solution:
    def strStr(self, haystack: str, needle: str) -> int:
        if needle == "":
            return 0

        lps = self._build_lps(needle)
        needle_index = 0

        for haystack_index, char in enumerate(haystack):
            while needle_index > 0 and char != needle[needle_index]:
                needle_index = lps[needle_index - 1]

            if char == needle[needle_index]:
                needle_index += 1
                if needle_index == len(needle):
                    return haystack_index - needle_index + 1

        return -1

    def _build_lps(self, pattern: str) -> list[int]:
        lps = [0] * len(pattern)
        prefix_length = 0

        # lps[i] stores the longest proper prefix that is also a suffix for pattern[: i + 1].
        for index in range(1, len(pattern)):
            while prefix_length > 0 and pattern[index] != pattern[prefix_length]:
                prefix_length = lps[prefix_length - 1]

            if pattern[index] == pattern[prefix_length]:
                prefix_length += 1
                lps[index] = prefix_length

        return lps

