import math


def xavier_limit(fan_in: int, fan_out: int) -> float:
    if fan_in <= 0 or fan_out <= 0:
        raise ValueError("fan_in and fan_out must be positive")
    return math.sqrt(6 / (fan_in + fan_out))


def xavier_uniform(fan_in: int, fan_out: int, seed: int = 0) -> list[float]:
    limit = xavier_limit(fan_in, fan_out)
    values: list[float] = []
    state = seed
    for _ in range(fan_in * fan_out):
        state = (1103515245 * state + 12345) % (2**31)
        values.append(-limit + (state / (2**31 - 1)) * (2 * limit))
    return values


def he_std(fan_in: int) -> float:
    if fan_in <= 0:
        raise ValueError("fan_in must be positive")
    return math.sqrt(2 / fan_in)


def he_normal(fan_in: int, fan_out: int, seed: int = 0) -> list[float]:
    if fan_out <= 0:
        raise ValueError("fan_out must be positive")
    std = he_std(fan_in)
    values: list[float] = []
    state = seed
    for _ in range(fan_in * fan_out // 2 + 1):
        state = (1103515245 * state + 12345) % (2**31)
        u1 = (state / (2**31 - 1)) or 1e-6
        state = (1103515245 * state + 12345) % (2**31)
        u2 = state / (2**31 - 1)
        z0 = math.sqrt(-2 * math.log(u1)) * math.cos(2 * math.pi * u2)
        z1 = math.sqrt(-2 * math.log(u1)) * math.sin(2 * math.pi * u2)
        values.extend([z0 * std, z1 * std])
    return values[: fan_in * fan_out]

import math


def _softmax(logits: list[float], temp: float) -> list[float]:
    if not logits:
        raise ValueError("logits must be non-empty")
    if temp <= 0.0:
        raise ValueError("temp must be positive")

    m = max(logits)
    exps = [math.exp((x - m) / temp) for x in logits]
    s = sum(exps)
    return [e / s for e in exps]


def distill_loss(student: list[float], teacher: list[float], temp: float = 1.0) -> float:
    if len(student) != len(teacher):
        raise ValueError("student and teacher must have the same length")

    ps = _softmax(student, temp)
    pt = _softmax(teacher, temp)
    loss = 0.0
    for p_s, p_t in zip(ps, pt):
        if p_t > 0 and p_s > 0:
            loss += p_t * math.log(p_t / p_s)
    return loss

fn softmax(logits: &[f64], temp: f64) -> Vec<f64> {
    assert!(!logits.is_empty(), "logits must be non-empty");
    assert!(temp > 0.0, "temp must be positive");

    let m = logits.iter().copied().fold(f64::NEG_INFINITY, f64::max);
    let exps: Vec<f64> = logits.iter().map(|x| ((x - m) / temp).exp()).collect();
    let sum: f64 = exps.iter().sum();
    exps.iter().map(|e| e / sum).collect()
}

pub fn distill_loss(student: &[f64], teacher: &[f64], temp: f64) -> f64 {
    assert_eq!(
        student.len(),
        teacher.len(),
        "student and teacher must have the same length"
    );

    let ps = softmax(student, temp);
    let pt = softmax(teacher, temp);
    let mut loss = 0.0;
    for (p_s, p_t) in ps.iter().zip(pt.iter()) {
        if *p_t > 0.0 && *p_s > 0.0 {
            loss += p_t * (p_t / p_s).ln();
        }
    }
    loss
}

