import math


def neuron(x: list[float], w: list[float], b: float) -> float:
    z = sum(weight * value for weight, value in zip(w, x)) + b
    return 1.0 / (1.0 + math.exp(-z))


def _matvec(weights: list[list[float]], x: list[float]) -> list[float]:
    return [sum(row[index] * x[index] for index in range(len(x))) for row in weights]


def _relu(x: list[float]) -> list[float]:
    return [max(0.0, value) for value in x]


def feedforward(
    x: list[float],
    weights: list[list[list[float]]],
    biases: list[list[float]],
) -> list[float]:
    hidden = x
    for weight_matrix, bias_vector in zip(weights, biases):
        hidden = [value + bias_vector[index] for index, value in enumerate(_matvec(weight_matrix, hidden))]
        hidden = _relu(hidden)
    return hidden

from __future__ import annotations

import math


def _validate_vector(x: list[float]) -> None:
    if not x:
        raise ValueError("x must be non-empty")


def _validate_matrix(matrix: list[list[float]]) -> None:
    if not matrix or not matrix[0]:
        raise ValueError("matrix must be non-empty")
    width = len(matrix[0])
    if any(len(row) != width for row in matrix):
        raise ValueError("matrix must be rectangular")


def _mean_variance(x: list[float]) -> tuple[float, float]:
    mean = sum(x) / len(x)
    variance = sum((value - mean) ** 2 for value in x) / len(x)
    return mean, variance


def mean_variance(x: list[float]) -> tuple[float, float]:
    _validate_vector(x)
    return _mean_variance(x)


def normalize_with_stats(x: list[float], mean: float, variance: float, eps: float = 1e-5) -> list[float]:
    if eps <= 0.0:
        raise ValueError("eps must be positive")
    return [(value - mean) / math.sqrt(variance + eps) for value in x]


def batch_stats(matrix: list[list[float]]) -> tuple[list[float], list[float]]:
    _validate_matrix(matrix)

    width = len(matrix[0])
    means: list[float] = []
    variances: list[float] = []
    for feature_index in range(width):
        column = [row[feature_index] for row in matrix]
        mean, variance = mean_variance(column)
        means.append(mean)
        variances.append(variance)
    return means, variances


def batchnorm(matrix: list[list[float]], eps: float = 1e-5) -> list[list[float]]:
    if eps <= 0.0:
        raise ValueError("eps must be positive")

    means, variances = batch_stats(matrix)
    return [
        [
            (value - means[feature_index]) / math.sqrt(variances[feature_index] + eps)
            for feature_index, value in enumerate(row)
        ]
        for row in matrix
    ]


def layernorm(x: list[float], eps: float = 1e-5) -> list[float]:
    mean, variance = mean_variance(x)
    return normalize_with_stats(x, mean, variance, eps=eps)


def rmsnorm(x: list[float], eps: float = 1e-5) -> list[float]:
    _validate_vector(x)
    rms = math.sqrt(sum(value * value for value in x) / len(x) + eps)
    return [value / rms for value in x]


def groupnorm(x: list[float], groups: int, eps: float = 1e-5) -> list[float]:
    _validate_vector(x)
    if groups <= 0:
        raise ValueError("groups must be positive")
    if len(x) % groups != 0:
        raise ValueError("len(x) must be divisible by groups")

    group_size = len(x) // groups
    out: list[float] = []
    for group_index in range(groups):
        chunk = x[group_index * group_size : (group_index + 1) * group_size]
        mean, variance = mean_variance(chunk)
        out.extend(normalize_with_stats(chunk, mean, variance, eps=eps))
    return out


def instancenorm(matrix: list[list[float]], eps: float = 1e-5) -> list[list[float]]:
    _validate_matrix(matrix)
    return [
        normalize_with_stats(row, *mean_variance(row), eps=eps)
        for row in matrix
    ]

from __future__ import annotations


def l1_penalty(weights: list[float], lam: float) -> float:
    return round(lam * sum(abs(weight) for weight in weights), 10)


def l2_penalty(weights: list[float], lam: float) -> float:
    return lam * sum(weight * weight for weight in weights)


def weight_decay_step(w: float, grad: float, lr: float, lam: float) -> float:
    return w - lr * (grad + lam * w)


def dropout(x: list[float], p: float, seed: int = 0) -> list[float]:
    if not 0.0 <= p < 1.0:
        raise ValueError("p must satisfy 0 <= p < 1")

    out: list[float] = []
    state = seed
    for value in x:
        state = (1103515245 * state + 12345) % (2**31)
        keep = (state / (2**31 - 1)) > p
        out.append(value / (1 - p) if keep else 0.0)
    return out


def should_stop(losses: list[float], patience: int) -> bool:
    best = float("inf")
    bad = 0
    for loss in losses:
        if loss < best:
            best = loss
            bad = 0
        else:
            bad += 1
            if bad >= patience:
                return True
    return False

