pub fn jacobian(f1: fn(f64, f64) -> f64, f2: fn(f64, f64) -> f64, x: f64, y: f64, eps: f64) -> [[f64; 2]; 2] {
    let df1_dx = (f1(x + eps, y) - f1(x - eps, y)) / (2.0 * eps);
    let df1_dy = (f1(x, y + eps) - f1(x, y - eps)) / (2.0 * eps);
    let df2_dx = (f2(x + eps, y) - f2(x - eps, y)) / (2.0 * eps);
    let df2_dy = (f2(x, y + eps) - f2(x, y - eps)) / (2.0 * eps);
    [[df1_dx, df1_dy], [df2_dx, df2_dy]]
}

import math


def js(p: list[float], q: list[float]) -> float:
    m = [(pi + qi) / 2 for pi, qi in zip(p, q)]
    def kl(a, b):
        return sum(ai * math.log(ai / bi) for ai, bi in zip(a, b) if ai > 0 and bi > 0)
    return 0.5 * kl(p, m) + 0.5 * kl(q, m)

pub fn js(p: &[f64], q: &[f64]) -> f64 {
    let m: Vec<f64> = p.iter().zip(q.iter()).map(|(a, b)| (a + b) / 2.0).collect();
    let kl = |a: &[f64], b: &[f64]| -> f64 {
        let mut total = 0.0;
        for (&ai, &bi) in a.iter().zip(b.iter()) {
            if ai > 0.0 && bi > 0.0 {
                total += ai * (ai / bi).ln();
            }
        }
        total
    };
    0.5 * kl(p, &m) + 0.5 * kl(q, &m)
}

import math


def kl(p: list[float], q: list[float]) -> float:
    if len(p) != len(q):
        raise ValueError("p and q must have the same length")

    total = 0.0
    for pi, qi in zip(p, q):
        if pi < 0.0 or qi < 0.0:
            raise ValueError("p and q must be non-negative")
        if pi == 0.0:
            continue
        if qi == 0.0:
            return float("inf")
        total += pi * math.log(pi / qi)
    return total

pub fn kl(p: &[f64], q: &[f64]) -> f64 {
    assert_eq!(p.len(), q.len(), "p and q must have the same length");

    let mut total = 0.0;
    for (&pi, &qi) in p.iter().zip(q.iter()) {
        assert!(pi >= 0.0 && qi >= 0.0, "p and q must be non-negative");
        if pi == 0.0 {
            continue;
        }
        if qi == 0.0 {
            return f64::INFINITY;
        }
        total += pi * (pi / qi).ln();
    }
    total
}

pub fn next_distribution(p: &[f64], t: &[Vec<f64>]) -> Vec<f64> {
    let mut out = vec![0.0; t[0].len()];
    for i in 0..t[0].len() {
        let mut sum = 0.0;
        for j in 0..p.len() {
            sum += p[j] * t[j][i];
        }
        out[i] = sum;
    }
    out
}

import math


def mutual_information(joint: list[list[float]]) -> float:
    px = [sum(row) for row in joint]
    py = [sum(joint[i][j] for i in range(len(joint))) for j in range(len(joint[0]))]
    mi = 0.0
    for i in range(len(joint)):
        for j in range(len(joint[0])):
            pxy = joint[i][j]
            if pxy > 0 and px[i] > 0 and py[j] > 0:
                mi += pxy * math.log(pxy / (px[i] * py[j]))
    return mi

pub fn mutual_information(joint: &[Vec<f64>]) -> f64 {
    let px: Vec<f64> = joint.iter().map(|row| row.iter().sum()).collect();
    let mut py = vec![0.0; joint[0].len()];
    for i in 0..joint.len() {
        for j in 0..joint[0].len() {
            py[j] += joint[i][j];
        }
    }
    let mut mi = 0.0;
    for i in 0..joint.len() {
        for j in 0..joint[0].len() {
            let pxy = joint[i][j];
            if pxy > 0.0 && px[i] > 0.0 && py[j] > 0.0 {
                mi += pxy * (pxy / (px[i] * py[j])).ln();
            }
        }
    }
    mi
}

pub fn newton_step(x: f64, f_prime: f64, f_double_prime: f64) -> f64 {
