def head_tail_keep(total_prompt_tokens: int, prompt_budget: int, head_tokens: int) -> tuple[int, int]:
    if total_prompt_tokens < 0:
        raise ValueError("total_prompt_tokens must be non-negative")
    if prompt_budget <= 0:
