from collections import Counter


def class_probabilities(labels: list[int]) -> list[float]:
    if not labels:
        return []
    counts = Counter(labels)
    n = len(labels)
    return [count / n for count in counts.values()]


def gini_impurity(labels: list[int]) -> float:
    if not labels:
        return 0.0
    return 1 - sum(probability**2 for probability in class_probabilities(labels))


def bootstrap_indices(n: int, seed: int = 0) -> list[int]:
    if n <= 0:
        raise ValueError("n must be positive")
    indices: list[int] = []
    state = seed
    for _ in range(n):
        state = (1103515245 * state + 12345) % (2**31)
        indices.append(state % n)
    return indices


def update_weights(weights: list[float], errors: list[int], alpha: float) -> list[float]:
    if len(weights) != len(errors):
        raise ValueError("weights and errors must have the same length")
    if any(weight < 0.0 for weight in weights):
        raise ValueError("weights must be non-negative")
    if any(error not in (0, 1) for error in errors):
        raise ValueError("errors must contain only 0 or 1")
    updated = [weight * math.exp(alpha * error) for weight, error in zip(weights, errors)]
    total = sum(updated)
    if total == 0.0:
        raise ValueError("updated weights must sum to a positive value")
    return [weight / total for weight in updated]


def gradient_boosting_step(
    targets: list[float],
    predictions: list[float],
    weak_learner_output: list[float],
    learning_rate: float,
) -> tuple[list[float], list[float]]:
    if len(targets) != len(predictions) or len(predictions) != len(weak_learner_output):
        raise ValueError("targets, predictions, and weak_learner_output must have the same length")
    if learning_rate < 0.0:
        raise ValueError("learning_rate must be non-negative")

    updated = [
        prediction + learning_rate * stage
        for prediction, stage in zip(predictions, weak_learner_output)
    ]
    residuals = boosting_residuals(targets, updated)
    return updated, residuals


def boosting_residuals(targets: list[float], predictions: list[float]) -> list[float]:
    if len(targets) != len(predictions):
        raise ValueError("targets and predictions must have the same length")
    return [target - prediction for target, prediction in zip(targets, predictions)]


def split_gain(
    left_grad: float,
    left_hess: float,
    right_grad: float,
    right_hess: float,
    lambda_reg: float,
    gamma: float,
) -> float:
    if left_hess < 0.0 or right_hess < 0.0 or lambda_reg < 0.0 or gamma < 0.0:
        raise ValueError("hessians, lambda_reg, and gamma must be non-negative")

    parent_grad = left_grad + right_grad
    parent_hess = left_hess + right_hess

    left_term = (left_grad ** 2) / (left_hess + lambda_reg)
    right_term = (right_grad ** 2) / (right_hess + lambda_reg)
    parent_term = (parent_grad ** 2) / (parent_hess + lambda_reg)
    return 0.5 * (left_term + right_term - parent_term) - gamma

from __future__ import annotations


def tsne_point_gradient(
    point: list[float],
    other_points: list[list[float]],
    affinities: list[float],
) -> list[float]:
    if len(other_points) != len(affinities):
        raise ValueError("other_points and affinities must have the same length")
    if any(len(other) != len(point) for other in other_points):
        raise ValueError("other_points must match the point dimension")
    if any(affinity < 0.0 for affinity in affinities):
        raise ValueError("affinities must be non-negative")
    if not other_points:
        return [0.0] * len(point)

    affinity_sum = sum(affinities)
    if affinity_sum <= 0.0:
        raise ValueError("affinities must sum to a positive value")
    normalized_affinities = [affinity / affinity_sum for affinity in affinities]

    numerators = []
    for other in other_points:
        squared_distance = sum((a - b) ** 2 for a, b in zip(point, other))
        numerators.append(1.0 / (1.0 + squared_distance))

    q_sum = sum(numerators)
    q_values = [numerator / q_sum for numerator in numerators]

    gradient = [0.0] * len(point)
    for p_ij, q_ij, numerator, other in zip(
        normalized_affinities, q_values, numerators, other_points
    ):
        coefficient = 4.0 * (p_ij - q_ij) * numerator
        for dimension in range(len(point)):
            gradient[dimension] += coefficient * (point[dimension] - other[dimension])
    return gradient

