pub fn clip_norm(grad: &[f64], clip: f64) -> Vec<f64> {
    let norm = grad.iter().map(|g| g * g).sum::<f64>().sqrt();
    if norm == 0.0 || norm <= clip {
        return grad.to_vec();
    }
    let scale = clip / norm;
    grad.iter().map(|g| g * scale).collect()
}

from __future__ import annotations

import math


def warmup_factor(t: int, warmup_steps: int) -> float:
    if warmup_steps <= 0:
        raise ValueError("warmup_steps must be positive")
    if t < 0:
        raise ValueError("t must be non-negative")
    return min(1.0, t / warmup_steps)


def cosine_decay_factor(t: int, t_max: int) -> float:
    if t_max <= 0:
        raise ValueError("t_max must be positive")
    return 0.5 * (1 + math.cos(math.pi * t / t_max))


def constant_lr(lr: float) -> float:
    return lr


def step_decay(lr: float, step: int, gamma: float, t: int) -> float:
    return lr * (gamma ** (t // step))


def exp_decay(lr: float, k: float, t: float) -> float:
    return lr * math.exp(-k * t)


def cosine_decay(lr: float, t: int, t_max: int) -> float:
    return lr * cosine_decay_factor(t, t_max)


def warmup_lr(lr: float, t: int, warmup_steps: int) -> float:
    return lr * warmup_factor(t, warmup_steps)


def cosine_restart_lr(base_lr: float, step: int, cycle_length: int) -> float:
    if base_lr < 0.0:
        raise ValueError("base_lr must be non-negative")
    if step < 0:
        raise ValueError("step must be non-negative")
    if cycle_length <= 0:
        raise ValueError("cycle_length must be positive")
    position = step % cycle_length
    return base_lr * cosine_decay_factor(position, cycle_length)


def warmup_cosine_lr(
    base_lr: float,
    step: int,
    warmup_steps: int,
    total_steps: int,
) -> float:
    if base_lr < 0.0:
        raise ValueError("base_lr must be non-negative")
    if step < 0:
        raise ValueError("step must be non-negative")
    if warmup_steps < 0:
        raise ValueError("warmup_steps must be non-negative")
    if total_steps <= 0:
        raise ValueError("total_steps must be positive")
    if warmup_steps > total_steps:
        raise ValueError("warmup_steps cannot exceed total_steps")

    if warmup_steps > 0 and step < warmup_steps:
        return base_lr * step / warmup_steps
    if total_steps == warmup_steps:
        return base_lr

    progress = (step - warmup_steps) / (total_steps - warmup_steps)
    progress = min(max(progress, 0.0), 1.0)
    return 0.5 * base_lr * (1.0 + math.cos(math.pi * progress))


def one_cycle_lr(
    max_lr: float,
    step: int,
    total_steps: int,
    pct_start: float = 0.3,
    div_factor: float = 25.0,
    final_div_factor: float = 1.0e4,
) -> float:
    if max_lr <= 0.0:
        raise ValueError("max_lr must be positive")
    if step < 0:
        raise ValueError("step must be non-negative")
    if total_steps <= 0:
        raise ValueError("total_steps must be positive")
    if not 0.0 < pct_start < 1.0:
        raise ValueError("pct_start must satisfy 0 < pct_start < 1")
    if div_factor <= 0.0 or final_div_factor <= 0.0:
        raise ValueError("div_factor and final_div_factor must be positive")

    if total_steps == 1:
        return max_lr

    initial_lr = max_lr / div_factor
    final_lr = initial_lr / final_div_factor
    last_step = total_steps - 1
    step = min(step, last_step)
    up_steps = max(1, int(last_step * pct_start))

    if step <= up_steps:
        progress = step / up_steps
        return initial_lr + progress * (max_lr - initial_lr)

    down_steps = last_step - up_steps
    progress = (step - up_steps) / down_steps
    cosine_weight = 0.5 * (1.0 + math.cos(math.pi * progress))
    return final_lr + cosine_weight * (max_lr - final_lr)

pub fn scale_grad(grad: f64, scale: f64) -> f64 {
    grad * scale
}

"""Muon optimizer demo using Gram-Schmidt orthogonalization."""

from __future__ import annotations

import math
from typing import List, Tuple


Matrix = List[List[float]]


def _dot(a: List[float], b: List[float]) -> float:
    return sum(x * y for x, y in zip(a, b))


def _norm(v: List[float]) -> float:
    return math.sqrt(_dot(v, v))


def gram_schmidt_rows(mat: Matrix, eps: float = 1e-12) -> Matrix:
    """Return an orthonormalized copy of rows via Gram-Schmidt."""
    out: Matrix = []
    for row in mat:
        v = row[:]
        for u in out:
            proj = _dot(v, u)
            v = [vi - proj * ui for vi, ui in zip(v, u)]
        n = _norm(v)
        if n < eps:
            out.append([0.0 for _ in v])
        else:
            out.append([vi / n for vi in v])
    return out


def muon_step(
    weights: Matrix,
    grad: Matrix,
    velocity: Matrix | None,
    lr: float = 0.1,
    momentum: float = 0.9,
) -> Tuple[Matrix, Matrix]:
    """Apply a Muon-style update and return (new_weights, new_velocity)."""
    if velocity is None:
        velocity = [[0.0 for _ in row] for row in grad]
    new_velocity = [
        [momentum * v + g for v, g in zip(v_row, g_row)]
        for v_row, g_row in zip(velocity, grad)
    ]
    ortho = gram_schmidt_rows(new_velocity)
    new_weights = [
        [w - lr * u for w, u in zip(w_row, u_row)]
        for w_row, u_row in zip(weights, ortho)
    ]
    return new_weights, new_velocity

pub type Matrix = Vec<Vec<f64>>;

fn dot(a: &[f64], b: &[f64]) -> f64 {
    a.iter().zip(b.iter()).map(|(x, y)| x * y).sum()
}

fn norm(v: &[f64]) -> f64 {
    dot(v, v).sqrt()
}

pub fn gram_schmidt_rows(mat: &Matrix, eps: f64) -> Matrix {
    let mut out: Matrix = Vec::new();
    for row in mat.iter() {
        let mut v = row.clone();
        for u in out.iter() {
            let proj = dot(&v, u);
            for (vi, ui) in v.iter_mut().zip(u.iter()) {
                *vi -= proj * ui;
            }
        }
        let n = norm(&v);
        if n < eps {
            out.push(vec![0.0; v.len()]);
        } else {
            out.push(v.iter().map(|vi| vi / n).collect());
        }
    }
    out
}

pub fn muon_step(
    weights: &Matrix,
    grad: &Matrix,
    velocity: Option<&Matrix>,
    lr: f64,
    momentum: f64,
) -> (Matrix, Matrix) {
    let mut vel = match velocity {
        Some(v) => v.clone(),
        None => grad.iter().map(|row| vec![0.0; row.len()]).collect(),
    };
    for (v_row, g_row) in vel.iter_mut().zip(grad.iter()) {
        for (v, g) in v_row.iter_mut().zip(g_row.iter()) {
            *v = momentum * *v + *g;
        }
    }
    let ortho = gram_schmidt_rows(&vel, 1e-12);
    let mut new_weights = weights.clone();
    for (w_row, u_row) in new_weights.iter_mut().zip(ortho.iter()) {
        for (w, u) in w_row.iter_mut().zip(u_row.iter()) {
            *w -= lr * u;
        }
    }
    (new_weights, vel)
}

from __future__ import annotations

import math


def momentum_velocity(grad: float, v: float, mu: float) -> float:
    if not 0.0 <= mu <= 1.0:
        raise ValueError("mu must satisfy 0 <= mu <= 1")
    return mu * v + grad


def sgd_step(w: float, grad: float, lr: float) -> float:
    if lr < 0.0:
        raise ValueError("lr must be non-negative")
    return w - lr * grad


def momentum_step(w: float, grad: float, v: float, lr: float, mu: float) -> tuple[float, float]:
    v = momentum_velocity(grad, v, mu)
    w = w - lr * v
    return w, v


def nesterov_step(w: float, grad: float, v: float, lr: float, mu: float) -> tuple[float, float]:
    v_new = momentum_velocity(grad, v, mu)
    w_new = w - lr * (mu * v_new + grad)
    return w_new, v_new


def adagrad_step(w: float, grad: float, g2: float, lr: float, eps: float) -> tuple[float, float]:
    if lr < 0.0:
        raise ValueError("lr must be non-negative")
    if g2 < 0.0:
        raise ValueError("g2 must be non-negative")
    if eps <= 0.0:
        raise ValueError("eps must be positive")
    g2 = g2 + grad**2
    w = w - lr * grad / (math.sqrt(g2) + eps)
    return w, g2


def rmsprop_step(w: float, grad: float, v: float, lr: float, beta: float, eps: float) -> tuple[float, float]:
    if lr < 0.0:
        raise ValueError("lr must be non-negative")
    if not 0.0 <= beta <= 1.0:
        raise ValueError("beta must satisfy 0 <= beta <= 1")
    if v < 0.0:
        raise ValueError("v must be non-negative")
    if eps <= 0.0:
        raise ValueError("eps must be positive")
    v = beta * v + (1 - beta) * (grad**2)
    w = w - lr * grad / (math.sqrt(v) + eps)
    return w, v


def adam_step(
    w: float, grad: float, m: float, v: float, lr: float, beta1: float, beta2: float, eps: float
) -> tuple[float, float, float]:
    if lr < 0.0:
        raise ValueError("lr must be non-negative")
    if not 0.0 <= beta1 <= 1.0 or not 0.0 <= beta2 <= 1.0:
        raise ValueError("beta1 and beta2 must satisfy 0 <= value <= 1")
    if v < 0.0:
        raise ValueError("v must be non-negative")
    if eps <= 0.0:
        raise ValueError("eps must be positive")
    m = beta1 * m + (1 - beta1) * grad
    v = beta2 * v + (1 - beta2) * (grad**2)
    w = w - lr * m / (math.sqrt(v) + eps)
    return w, m, v


def adamw_step(
    w: float,
    grad: float,
    m: float,
    v: float,
    lr: float,
    wd: float,
    beta1: float,
    beta2: float,
    eps: float,
) -> tuple[float, float, float]:
    if wd < 0.0:
        raise ValueError("wd must be non-negative")
    m = beta1 * m + (1 - beta1) * grad
    v = beta2 * v + (1 - beta2) * (grad**2)
    w = w - lr * m / (math.sqrt(v) + eps) - weight_decay_term(w, lr=lr, wd=wd)
    return w, m, v


def weight_decay_term(w: float, lr: float, wd: float) -> float:
    if lr < 0.0:
        raise ValueError("lr must be non-negative")
    if wd < 0.0:
        raise ValueError("wd must be non-negative")
    return lr * wd * w

from __future__ import annotations

import math


def incremental_mean(estimate: float, pull_count: int, reward: float) -> float:
    if pull_count <= 0:
        raise ValueError("pull_count must be positive")
    return estimate + (reward - estimate) / pull_count


def epsilon_greedy_probs(action_values: list[float], epsilon: float) -> list[float]:
    if not action_values:
        raise ValueError("action_values must be non-empty")
    if not 0.0 <= epsilon <= 1.0:
        raise ValueError("epsilon must satisfy 0 <= epsilon <= 1")

    num_actions = len(action_values)
    max_value = max(action_values)
    best_actions = [index for index, value in enumerate(action_values) if value == max_value]

    probs = [epsilon / num_actions] * num_actions
    greedy_mass = (1.0 - epsilon) / len(best_actions)
    for index in best_actions:
        probs[index] += greedy_mass
    return probs


def ucb_scores(action_values: list[float], total_steps: int, pull_counts: list[int], c: float = 1.0) -> list[float]:
    if len(action_values) != len(pull_counts):
        raise ValueError("action_values and pull_counts must have the same length")
    if not action_values:
        raise ValueError("action_values and pull_counts must be non-empty")
    if total_steps <= 0:
        raise ValueError("total_steps must be positive")
    if c < 0.0:
        raise ValueError("c must be non-negative")

    scores: list[float] = []
    for value, pulls in zip(action_values, pull_counts):
        if pulls < 0:
            raise ValueError("pull_counts must be non-negative")
        if pulls == 0:
            scores.append(float("inf"))
            continue
        bonus = c * math.sqrt(math.log(total_steps) / pulls)
        scores.append(value + bonus)
    return scores

