"""Group-based optimization demo for GRPO/GSPO."""

from __future__ import annotations

import math
from typing import List


def group_advantages(rewards: List[float], eps: float = 1e-8) -> List[float]:
    if not rewards:
        return []
    mean = sum(rewards) / len(rewards)
    var = sum((r - mean) ** 2 for r in rewards) / len(rewards)
    std = math.sqrt(var)
    return [(r - mean) / (std + eps) for r in rewards]


def _sequence_ratio(old_logps: List[float], new_logps: List[float]) -> float:
    return math.exp(sum(n - o for o, n in zip(old_logps, new_logps)))


def _token_ratio_mean(old_logps: List[float], new_logps: List[float]) -> float:
    ratios = [math.exp(n - o) for o, n in zip(old_logps, new_logps)]
    return sum(ratios) / len(ratios)


def grpo_objective(
    old_logps: List[List[float]],
    new_logps: List[List[float]],
    rewards: List[float],
) -> float:
    advantages = group_advantages(rewards)
    if not advantages:
        return 0.0
    total = 0.0
    for old, new, adv in zip(old_logps, new_logps, advantages):
        total += _token_ratio_mean(old, new) * adv
    return total / len(advantages)


def gspo_objective(
    old_logps: List[List[float]],
    new_logps: List[List[float]],
    rewards: List[float],
) -> float:
    advantages = group_advantages(rewards)
    if not advantages:
        return 0.0
    total = 0.0
    for old, new, adv in zip(old_logps, new_logps, advantages):
        total += _sequence_ratio(old, new) * adv
    return total / len(advantages)

pub fn group_advantages(rewards: &[f64]) -> Vec<f64> {
    if rewards.is_empty() {
        return Vec::new();
    }
    let mean = rewards.iter().sum::<f64>() / rewards.len() as f64;
    let var = rewards
        .iter()
        .map(|r| (r - mean).powi(2))
        .sum::<f64>()
        / rewards.len() as f64;
    let std = var.sqrt();
    rewards
        .iter()
        .map(|r| (r - mean) / (std + 1e-8))
        .collect()
}

fn sequence_ratio(old_logps: &[f64], new_logps: &[f64]) -> f64 {
    let sum_delta: f64 = old_logps
        .iter()
        .zip(new_logps.iter())
        .map(|(o, n)| n - o)
        .sum();
    sum_delta.exp()
}

fn token_ratio_mean(old_logps: &[f64], new_logps: &[f64]) -> f64 {
    let ratios: f64 = old_logps
        .iter()
        .zip(new_logps.iter())
        .map(|(o, n)| (n - o).exp())
        .sum();
    ratios / old_logps.len() as f64
}

pub fn grpo_objective(old_logps: &[Vec<f64>], new_logps: &[Vec<f64>], rewards: &[f64]) -> f64 {
    let advantages = group_advantages(rewards);
    if advantages.is_empty() {
        return 0.0;
    }
    let mut total = 0.0;
    for ((old, new), adv) in old_logps.iter().zip(new_logps.iter()).zip(advantages.iter()) {
        total += token_ratio_mean(old, new) * adv;
    }
    total / advantages.len() as f64
}

pub fn gspo_objective(old_logps: &[Vec<f64>], new_logps: &[Vec<f64>], rewards: &[f64]) -> f64 {
    let advantages = group_advantages(rewards);
    if advantages.is_empty() {
        return 0.0;
    }
    let mut total = 0.0;
    for ((old, new), adv) in old_logps.iter().zip(new_logps.iter()).zip(advantages.iter()) {
        total += sequence_ratio(old, new) * adv;
    }
    total / advantages.len() as f64
}

use std::collections::HashMap;

pub fn transition_prob(
    transitions: &HashMap<(i32, i32), HashMap<i32, f64>>,
    s: i32,
    a: i32,
    s_next: i32,
) -> f64 {
    transitions
        .get(&(s, a))
        .and_then(|m| m.get(&s_next).copied())
        .unwrap_or(0.0)
}

from __future__ import annotations

import math


def uct_score(
    value_sum: float,
    parent_visits: int,
    child_visits: int,
    exploration: float = 1.4142135623730951,
) -> float:
    if parent_visits <= 0:
        raise ValueError("parent_visits must be positive")
    if child_visits < 0:
        raise ValueError("child_visits must be non-negative")
    if exploration < 0.0:
        raise ValueError("exploration must be non-negative")
    if child_visits == 0:
        return math.inf

    mean_value = value_sum / child_visits
    bonus = exploration * math.sqrt(math.log(parent_visits) / child_visits)
    return mean_value + bonus

from __future__ import annotations


def _validate_inputs(rewards: list[float], target_probs: list[float], behavior_probs: list[float]) -> None:
    if len(rewards) != len(target_probs) or len(rewards) != len(behavior_probs):
        raise ValueError("rewards, target_probs, and behavior_probs must have the same length")
    if any(probability < 0.0 for probability in target_probs + behavior_probs):
        raise ValueError("probabilities must be non-negative")
    if any(probability == 0.0 for probability in behavior_probs):
        raise ValueError("behavior_probs must be strictly positive")


def importance_weights(target_probs: list[float], behavior_probs: list[float]) -> list[float]:
    if len(target_probs) != len(behavior_probs):
        raise ValueError("target_probs and behavior_probs must have the same length")
    if any(probability < 0.0 for probability in target_probs + behavior_probs):
        raise ValueError("probabilities must be non-negative")
    if any(probability == 0.0 for probability in behavior_probs):
        raise ValueError("behavior_probs must be strictly positive")
    return [target_prob / behavior_prob for target_prob, behavior_prob in zip(target_probs, behavior_probs)]


def importance_sampling_estimate(
    rewards: list[float],
    target_probs: list[float],
    behavior_probs: list[float],
) -> float:
    _validate_inputs(rewards, target_probs, behavior_probs)
    if not rewards:
        return 0.0

    weights = importance_weights(target_probs, behavior_probs)
    weighted_sum = sum(reward * weight for reward, weight in zip(rewards, weights))
    return weighted_sum / len(rewards)


def weighted_importance_sampling_estimate(
    rewards: list[float],
    target_probs: list[float],
    behavior_probs: list[float],
) -> float:
    _validate_inputs(rewards, target_probs, behavior_probs)
    if not rewards:
        return 0.0

    weights = importance_weights(target_probs, behavior_probs)
    weighted_sum = sum(reward * weight for reward, weight in zip(rewards, weights))
    total_weight = sum(weights)
    if total_weight == 0.0:
        return 0.0
    return weighted_sum / total_weight


def off_policy_estimates(
    rewards: list[float],
    target_probs: list[float],
    behavior_probs: list[float],
) -> tuple[float, float]:
    ordinary = importance_sampling_estimate(rewards, target_probs, behavior_probs)
    weighted = weighted_importance_sampling_estimate(rewards, target_probs, behavior_probs)
    return ordinary, weighted

from __future__ import annotations


def reinforce_update(grad_logp: float, reward: float, lr: float) -> float:
    return lr * reward * grad_logp


def clip_ratio(ratio: float, eps: float) -> float:
    if eps < 0.0:
        raise ValueError("eps must be non-negative")
    return max(1.0 - eps, min(1.0 + eps, ratio))


def td_residuals(
    rewards: list[float],
    values: list[float],
    gamma: float,
    next_value: float = 0.0,
) -> list[float]:
    if len(rewards) != len(values):
        raise ValueError("rewards and values must have the same length")
    if not 0.0 <= gamma <= 1.0:
        raise ValueError("gamma must satisfy 0 <= gamma <= 1")

    deltas: list[float] = []
    for index, (reward, value) in enumerate(zip(rewards, values)):
        bootstrapped_value = next_value if index == len(rewards) - 1 else values[index + 1]
        deltas.append(reward + gamma * bootstrapped_value - value)
    return deltas


def ppo_objective_term(ratio: float, advantage: float, eps: float) -> float:
    clipped_ratio = clip_ratio(ratio, eps)
    unclipped = ratio * advantage
    clipped = clipped_ratio * advantage
    return min(unclipped, clipped)


def generalized_advantages(
    rewards: list[float],
    values: list[float],
    gamma: float,
    lam: float,
    next_value: float = 0.0,
) -> list[float]:
    if not 0.0 <= lam <= 1.0:
        raise ValueError("lam must satisfy 0 <= lam <= 1")

    deltas = td_residuals(rewards, values, gamma=gamma, next_value=next_value)
    advantages = [0.0] * len(rewards)
    running_advantage = 0.0

    for index in range(len(rewards) - 1, -1, -1):
        running_advantage = deltas[index] + gamma * lam * running_advantage
        advantages[index] = running_advantage

    return advantages

from __future__ import annotations

import math


def policy_entropy(probabilities: list[float]) -> float:
    if not probabilities:
        return 0.0
    if any(probability < 0.0 for probability in probabilities):
        raise ValueError("probabilities must be non-negative")

    total_probability = sum(probabilities)
    if not math.isclose(total_probability, 1.0, rel_tol=1.0e-9, abs_tol=1.0e-9):
        raise ValueError("probabilities must sum to 1")

    return -sum(probability * math.log(probability) for probability in probabilities if probability > 0.0)


def entropy_bonus(probabilities: list[float], coefficient: float) -> float:
    if coefficient < 0.0:
        raise ValueError("coefficient must be non-negative")
    return coefficient * policy_entropy(probabilities)


def normalize_advantages(advantages: list[float], eps: float = 1.0e-8) -> list[float]:
    if eps < 0.0:
        raise ValueError("eps must be non-negative")
    if not advantages:
        return []

    mean = sum(advantages) / len(advantages)
    variance = sum((advantage - mean) ** 2 for advantage in advantages) / len(advantages)
    std = math.sqrt(variance)
    return [(advantage - mean) / (std + eps) for advantage in advantages]


def normalize_value_targets(values: list[float], eps: float = 1.0e-8) -> tuple[list[float], float, float]:
    if eps < 0.0:
        raise ValueError("eps must be non-negative")
    if not values:
        return [], 0.0, 0.0

    mean = sum(values) / len(values)
    variance = sum((value - mean) ** 2 for value in values) / len(values)
    std = math.sqrt(variance)
    normalized = [(value - mean) / (std + eps) for value in values]
    return normalized, mean, std


def reward_scale(rewards: list[float]) -> float:
    if not rewards:
        return 0.0
    return sum(abs(reward) for reward in rewards) / len(rewards)


def clip_rewards(rewards: list[float], min_reward: float = -1.0, max_reward: float = 1.0) -> list[float]:
    if min_reward > max_reward:
        raise ValueError("min_reward cannot exceed max_reward")
    return [min(max(reward, min_reward), max_reward) for reward in rewards]

from __future__ import annotations


def discounted_return(rewards: list[float], gamma: float) -> float:
    if not 0.0 <= gamma <= 1.0:
        raise ValueError("gamma must satisfy 0 <= gamma <= 1")
    total = 0.0
    for step, reward in enumerate(rewards):
        total += (gamma ** step) * reward
    return total


def n_step_return(rewards: list[float], gamma: float, bootstrap_value: float = 0.0) -> float:
    if not 0.0 <= gamma <= 1.0:
        raise ValueError("gamma must satisfy 0 <= gamma <= 1")

    total = discounted_return(rewards, gamma)
    return total + (gamma ** len(rewards)) * bootstrap_value


def n_step_td_target(rewards: list[float], bootstrap_value: float, gamma: float) -> float:
    return n_step_return(rewards=rewards, gamma=gamma, bootstrap_value=bootstrap_value)


def td_lambda_returns(
    rewards: list[float],
    next_state_values: list[float],
    gamma: float,
    lam: float,
    terminal_value: float = 0.0,
) -> list[float]:
    if len(rewards) != len(next_state_values):
        raise ValueError("rewards and next_state_values must have the same length")
    if not 0.0 <= gamma <= 1.0:
        raise ValueError("gamma must satisfy 0 <= gamma <= 1")
    if not 0.0 <= lam <= 1.0:
        raise ValueError("lam must satisfy 0 <= lam <= 1")

    lambda_returns = [0.0] * len(rewards)
    future_return = terminal_value

    for index in range(len(rewards) - 1, -1, -1):
        bootstrap = next_state_values[index]
        future_return = rewards[index] + gamma * ((1.0 - lam) * bootstrap + lam * future_return)
        lambda_returns[index] = future_return

    return lambda_returns


def first_visit_returns(states: list[str], rewards: list[float], gamma: float) -> dict[str, float]:
    if len(states) != len(rewards):
        raise ValueError("states and rewards must have the same length")
    if not 0.0 <= gamma <= 1.0:
        raise ValueError("gamma must satisfy 0 <= gamma <= 1")

    returns: dict[str, float] = {}
    running_return = 0.0

    for timestep in range(len(states) - 1, -1, -1):
        running_return = rewards[timestep] + gamma * running_return
        if states[timestep] not in states[:timestep]:
            returns[states[timestep]] = running_return

    return returns

from __future__ import annotations


def bootstrap_target(reward: float, gamma: float, next_value: float, done: bool = False) -> float:
    if not 0.0 <= gamma <= 1.0:
        raise ValueError("gamma must satisfy 0 <= gamma <= 1")
    if done:
        return reward
    return reward + gamma * next_value


def q_learning_target(reward: float, gamma: float, next_q_values: list[float], done: bool = False) -> float:
    if done:
        return bootstrap_target(reward, gamma, next_value=0.0, done=True)
    if not next_q_values:
        raise ValueError("next_q_values must be non-empty")
    return bootstrap_target(reward, gamma, next_value=max(next_q_values))


def sarsa_target(reward: float, gamma: float, next_q: float, done: bool = False) -> float:
    return bootstrap_target(reward, gamma, next_value=next_q, done=done)


def expected_sarsa_target(
    reward: float,
    gamma: float,
    next_action_probs: list[float],
    next_q_values: list[float],
    done: bool = False,
) -> float:
    if done:
        return bootstrap_target(reward, gamma, next_value=0.0, done=True)
    if len(next_action_probs) != len(next_q_values):
        raise ValueError("next_action_probs and next_q_values must have the same length")
    if not next_action_probs:
        raise ValueError("next_action_probs and next_q_values must be non-empty")
    if any(probability < 0.0 for probability in next_action_probs):
        raise ValueError("next_action_probs must be non-negative")
    if abs(sum(next_action_probs) - 1.0) > 1e-9:
        raise ValueError("next_action_probs must sum to 1")

    expected_next_value = sum(probability * q_value for probability, q_value in zip(next_action_probs, next_q_values))
    return bootstrap_target(reward, gamma, next_value=expected_next_value)


def double_q_target(
    reward: float,
    gamma: float,
    selector_values: list[float],
    evaluator_values: list[float],
    done: bool = False,
) -> float:
    if done:
        return bootstrap_target(reward, gamma, next_value=0.0, done=True)
    if len(selector_values) != len(evaluator_values):
        raise ValueError("selector_values and evaluator_values must have the same length")
    if not selector_values:
        raise ValueError("selector_values and evaluator_values must be non-empty")

    best_action = max(range(len(selector_values)), key=selector_values.__getitem__)
    return bootstrap_target(reward, gamma, next_value=evaluator_values[best_action])


def td_error(value: float, target: float) -> float:
    return target - value


def td_update(value: float, target: float, alpha: float) -> float:
    if not 0.0 <= alpha <= 1.0:
        raise ValueError("alpha must satisfy 0 <= alpha <= 1")
    return value + alpha * td_error(value=value, target=target)


def soft_target_update(target_values: list[float], online_values: list[float], tau: float) -> list[float]:
    if len(target_values) != len(online_values):
        raise ValueError("target_values and online_values must have the same length")
    if not 0.0 <= tau <= 1.0:
        raise ValueError("tau must satisfy 0 <= tau <= 1")

    return [
        (1.0 - tau) * target_value + tau * online_value
        for target_value, online_value in zip(target_values, online_values)
    ]


def soft_update_gap(target_values: list[float], online_values: list[float], tau: float) -> float:
    if len(target_values) != len(online_values):
        raise ValueError("target_values and online_values must have the same length")
    if not 0.0 <= tau <= 1.0:
        raise ValueError("tau must satisfy 0 <= tau <= 1")
    if not target_values:
        return 0.0

    updated = soft_target_update(target_values, online_values, tau)
    gaps = [abs(online_value - updated_value) for online_value, updated_value in zip(online_values, updated)]
    return sum(gaps) / len(gaps)

