def _matvec(matrix: list[list[float]], vector: list[float]) -> list[float]:
    return [sum(m * v for m, v in zip(row, vector)) for row in matrix]


def _transpose(matrix: list[list[float]]) -> list[list[float]]:
    if not matrix:
        return []
    return [list(row) for row in zip(*matrix)]


def linear_autoencode(x: list[float], W: list[list[float]]) -> list[float]:
    if not W:
        return []
    z = _matvec(W, x)
    Wt = _transpose(W)
    return _matvec(Wt, z)

import math


def _cosine_similarity(a: list[float], b: list[float]) -> float:
    dot = sum(x * y for x, y in zip(a, b))
    norm_a = math.sqrt(sum(x * x for x in a))
    norm_b = math.sqrt(sum(y * y for y in b))
    if norm_a == 0.0 or norm_b == 0.0:
        return 0.0
    return dot / (norm_a * norm_b)


def info_nce_loss(
    anchor: list[float],
    positive: list[float],
    negatives: list[list[float]],
    temperature: float = 0.1,
) -> float:
    if temperature <= 0:
        raise ValueError("temperature must be positive")

    pos_score = math.exp(_cosine_similarity(anchor, positive) / temperature)
    neg_scores = [math.exp(_cosine_similarity(anchor, n) / temperature) for n in negatives]
    denom = pos_score + sum(neg_scores)
    return -math.log(pos_score / denom)

def bag_of_words(tokens: list[str], vocab: list[str]) -> list[int]:
    index = {token: i for i, token in enumerate(vocab)}
    counts = [0] * len(vocab)
    for token in tokens:
        position = index.get(token)
        if position is not None:
            counts[position] += 1
    return counts

