import math


def pairwise_logistic_loss(preferred_score: float, rejected_score: float) -> float:
    margin = preferred_score - rejected_score
    if margin >= 0.0:
        return math.log1p(math.exp(-margin))
    return -margin + math.log1p(math.exp(margin))

from __future__ import annotations


def triplet_loss(
    anchor_positive_distance: float,
    anchor_negative_distance: float,
    margin: float = 0.2,
) -> float:
    if margin < 0.0:
        raise ValueError("margin must be non-negative")
    if anchor_positive_distance < 0.0 or anchor_negative_distance < 0.0:
        raise ValueError("distances must be non-negative")

    return max(0.0, anchor_positive_distance - anchor_negative_distance + margin)

from __future__ import annotations


def chunked_prefill_rounds(prompt_lengths: list[int], chunk_size: int) -> list[int]:
    if chunk_size <= 0:
        raise ValueError("chunk_size must be positive")
    if any(length <= 0 for length in prompt_lengths):
        raise ValueError("prompt_lengths must be positive")
    if not prompt_lengths:
        return []

    remaining = prompt_lengths[:]
    rounds: list[int] = []

    while any(length > 0 for length in remaining):
        round_tokens = sum(min(length, chunk_size) for length in remaining)
        rounds.append(round_tokens)
        remaining = [max(length - chunk_size, 0) for length in remaining]

    return rounds

