import math


def context_parallel_attention_stats(
    sequence_length: int,
    hidden_size: int,
    num_shards: int,
    bytes_per_element: int = 2,
) -> tuple[int, int]:
    if sequence_length <= 0:
        raise ValueError("sequence_length must be positive")
    if hidden_size <= 0:
        raise ValueError("hidden_size must be positive")
    if num_shards <= 0:
        raise ValueError("num_shards must be positive")
    if bytes_per_element <= 0:
        raise ValueError("bytes_per_element must be positive")

    local_tokens = math.ceil(sequence_length / num_shards)
    remote_tokens = max(sequence_length - local_tokens, 0)
    remote_kv_bytes = 2 * remote_tokens * hidden_size * bytes_per_element
    return local_tokens, remote_kv_bytes

def diagnose(train_loss: float, val_loss: float) -> str:
    if train_loss < val_loss * 0.7:
        return "overfit"
    if train_loss > 1.0 and val_loss > 1.0:
        return "underfit"
    return "ok"

pub fn diagnose(train_loss: f64, val_loss: f64) -> String {
    if train_loss < val_loss * 0.7 {
        "overfit".to_string()
    } else if train_loss > 1.0 && val_loss > 1.0 {
        "underfit".to_string()
    } else {
        "ok".to_string()
    }
}

from __future__ import annotations


def expert_load_balance_loss(
    router_probs: list[list[float]],
    assignments: list[int],
) -> float:
    if len(router_probs) != len(assignments):
        raise ValueError("router_probs and assignments must have the same length")
    if not router_probs:
        return 0.0

    num_experts = len(router_probs[0])
    if num_experts == 0:
        raise ValueError("router_probs must include at least one expert")
    if any(len(row) != num_experts for row in router_probs):
        raise ValueError("all router_probs rows must have the same length")
    if any(index < 0 or index >= num_experts for index in assignments):
        raise ValueError("assignments must be valid expert indices")

    token_fractions = [0.0] * num_experts
    prob_fractions = [0.0] * num_experts
    num_tokens = len(assignments)

    for assignment in assignments:
        token_fractions[assignment] += 1.0 / num_tokens
    for row in router_probs:
        for expert, probability in enumerate(row):
            prob_fractions[expert] += probability / num_tokens

    return num_experts * sum(
        token_fraction * prob_fraction
        for token_fraction, prob_fraction in zip(token_fractions, prob_fractions)
    )

from __future__ import annotations


def expert_parallel_dispatch_stats(
    token_home_shards: list[int],
    expert_assignments: list[int],
    experts_per_shard: int,
) -> tuple[list[int], int]:
    if len(token_home_shards) != len(expert_assignments):
        raise ValueError("token_home_shards and expert_assignments must have the same length")
    if experts_per_shard <= 0:
        raise ValueError("experts_per_shard must be positive")
    if any(shard < 0 for shard in token_home_shards):
        raise ValueError("token_home_shards must be non-negative")
    if any(expert < 0 for expert in expert_assignments):
        raise ValueError("expert_assignments must be non-negative")
    if not token_home_shards:
        return [], 0

    max_target_shard = max(expert // experts_per_shard for expert in expert_assignments)
    num_shards = max(max(token_home_shards), max_target_shard) + 1

    load_per_shard = [0] * num_shards
    remote_dispatches = 0

    for home_shard, expert in zip(token_home_shards, expert_assignments):
        target_shard = expert // experts_per_shard
        load_per_shard[target_shard] += 1
        if target_shard != home_shard:
            remote_dispatches += 1

    return load_per_shard, remote_dispatches

from __future__ import annotations


def prefix_cache_savings(
    prompt_lengths: list[int],
    hit_lengths: list[int],
) -> tuple[int, float]:
    if len(prompt_lengths) != len(hit_lengths):
        raise ValueError("prompt_lengths and hit_lengths must have the same length")
    if any(length <= 0 for length in prompt_lengths):
        raise ValueError("prompt_lengths must be positive")

    saved_tokens = 0
    total_tokens = sum(prompt_lengths)
    for prompt_length, hit_length in zip(prompt_lengths, hit_lengths):
        if hit_length < 0:
            raise ValueError("hit_lengths must be non-negative")
        if hit_length > prompt_length:
            raise ValueError("hit_length cannot exceed prompt_length")
        saved_tokens += hit_length

    return saved_tokens, saved_tokens / total_tokens

from __future__ import annotations


def row_parallel_linear_stats(
    batch_tokens: int,
    input_dim: int,
    output_dim: int,
    num_shards: int,
    bytes_per_element: int = 2,
) -> tuple[int, int]:
    if batch_tokens <= 0:
        raise ValueError("batch_tokens must be positive")
    if input_dim <= 0:
        raise ValueError("input_dim must be positive")
    if output_dim <= 0:
        raise ValueError("output_dim must be positive")
    if num_shards <= 0:
        raise ValueError("num_shards must be positive")
    if bytes_per_element <= 0:
        raise ValueError("bytes_per_element must be positive")
    if input_dim % num_shards != 0:
        raise ValueError("input_dim must be divisible by num_shards")

    local_input_dim = input_dim // num_shards
    all_reduce_bytes = batch_tokens * output_dim * bytes_per_element
    return local_input_dim, all_reduce_bytes

